import { format } from 'date-fns'
export const COLUMNS = [
    {
        Header: 'ID',
        Footer: 'ID',
        accessor: 'id'
    },
    {
        Header: 'Student ID',
        Footer: 'Student ID',
        accessor: 'studentID'
    },
    {
        Header: 'Name',
        Footer: 'Name',
        accessor: 'name'
    },
    {
        Header: 'Password',
        Footer: 'Password',
        accessor: 'password'
    },
    {
        Header: 'Date Created',
        Footer: 'Date Created',
        accessor: 'dateCreated',
        Cell: ({ value }) => {return format(new Date(value), 'dd/MM/yyyy mm/hh/ss')}
    }
]
